#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long P, Q; // P,Q can be up to 26*N (fits in 64‑bit)
        scanf("%d %lld %lld", &N, &P, &Q);
        char s[200005];
        scanf("%s", s);
        for(int i=0;i<N;i++){
            int c = s[i]-'a';
            for(int t=0;t<26;t++){
                int up = (t - c + 26) % 26;
                int down = (c - t + 26) % 26;
                if(up<=P){
                    s[i] = 'a'+t;
                    P -= up;
                    break;
                }
                if(down<=Q){
                    s[i] = 'a'+t;
                    Q -= down;
                    break;
                }
            }
        }
        printf("%s\n", s);
    }
    return 0;
}

