const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let tc = 0; tc < T; tc++) {
  const N = Number(input[idx++]);
  let P = Number(input[idx++]);
  let Q = Number(input[idx++]);
  let s = input[idx++].split('');
  for (let i = 0; i < N; i++) {
    const c = s[i].charCodeAt(0) - 97;
    for (let t = 0; t < 26; t++) {
      const up = (t - c + 26) % 26;
      const down = (c - t + 26) % 26;
      if (up <= P) {
        s[i] = String.fromCharCode(97 + t);
        P -= up;
        break;
      }
      if (down <= Q) {
        s[i] = String.fromCharCode(97 + t);
        Q -= down;
        break;
      }
    }
  }
  results.push(s.join(''));
}
